main();function main(){setColorScheme(),window.matchMedia("(prefers-color-scheme: dark)").addEventListener("change",setColorScheme)}function setColorScheme(){setMetaThemeColour(getBackgroundColour())}function getBackgroundColour(){return window.getComputedStyle(document.documentElement).getPropertyValue("--background")}function setMetaThemeColour(e){document.querySelector('meta[name="theme-color"]').setAttribute("content",e)}